mapper.select:
select id, title, content, cover_img, category_id, user_id, status, audit_reason, is_top, view_count, like_count, favorite_count, comment_count, create_time, update_time from content
and title like concat('%', #{title}, '%')
and category_id = #{categoryId}
and status = #{status}
order by is_top desc, create_time desc

select count(1)
from content
where category_id = #{categoryId}

select count(1)
from content
where user_id = #{userId}
